SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND (t.D_RSI_Max1W/ NULLIF(t.D_RSI, 0) > 0.88) AND (t.D_RSI_T1/ NULLIF(t.D_RSI, 0) > 1.11) AND (t.D_RSI_Max3M > 0.66) AND (t.D_RSI_Max1W < 0.76) AND (t.D_RSI_Max1W >0.57) AND (t.D_RSI_Max1W_Close/ NULLIF(t.D_RSI_Max3M_Close, 0) > 1.12) AND (t.D_RSI_Max3M_MACD/ NULLIF(t.D_RSI_Max1W_MACD, 0) > 1.29) AND (t.Volume > 1.11*t.Volume_1M) AND (t.D_RSI_Max3M/ NULLIF(t.D_RSI_Max1W, 0) > 1.21) ORDER BY t.ticker, t.time